buffer_pool_t *buffer_pool_create(int pool_size, int buffer_size) {
    buffer_pool_t *pool = (buffer_pool_t *)malloc(sizeof(buffer_pool_t));
    if (!pool) return NULL;

    pool->pool_size = pool_size > 16 ? 16 : pool_size;
    pool->buffer_size = buffer_size;

    for (int i = 0; i < pool->pool_size; i++) {
        pool->buffers[i] = (char *)malloc(buffer_size);
        pool->in_use[i] = false;
        if (!pool->buffers[i]) {
            for (int j = 0; j < i; j++) {
                free(pool->buffers[j]);
            }
            free(pool);
            return NULL;
        }
    }

    return pool;
}

char *buffer_pool_acquire(buffer_pool_t *pool) {
    if (!pool) return NULL;
    for (int i = 0; i < pool->pool_size; i++) {
        if (!pool->in_use[i]) {
            pool->in_use[i] = true;
            memset(pool->buffers[i], 0, pool->buffer_size);
            return pool->buffers[i];
        }
    }
    /* Pool exhausted, fall back to malloc */
    return (char *)calloc(1, pool->buffer_size);
}

void buffer_pool_release(buffer_pool_t *pool, char *buffer) {
    if (!pool || !buffer) return;
    for (int i = 0; i < pool->pool_size; i++) {
        if (pool->buffers[i] == buffer) {
            pool->in_use[i] = false;
            return;
        }
    }
    /* Buffer was not from pool, free it */
    free(buffer);
}

void buffer_pool_destroy(buffer_pool_t *pool) {
    if (!pool) return;
    for (int i = 0; i < pool->pool_size; i++) {
        free(pool->buffers[i]);
    }
    free(pool);
}

http_method_t parse_method(const char *method_str) {
    if (strncmp(method_str, "GET", 3) == 0) return HTTP_GET;
    if (strncmp(method_str, "POST", 4) == 0) return HTTP_POST;
    if (strncmp(method_str, "PUT", 3) == 0) return HTTP_PUT;
    if (strncmp(method_str, "DELETE", 6) == 0) return HTTP_DELETE;
    return HTTP_UNKNOWN;
}

const char *method_to_string(http_method_t method) {
    switch (method) {
        case HTTP_GET: return "GET";
        case HTTP_POST: return "POST";
        case HTTP_PUT: return "PUT";
        case HTTP_DELETE: return "DELETE";
        default: return "UNKNOWN";
    }
}

int parse_request(const char *raw_request, size_t raw_length, http_request_t *request) {
    if (!raw_request || !request || raw_length == 0) return -1;

    memset(request, 0, sizeof(http_request_t));
    request->total_size = raw_length;

    /* Parse request line */
    char method_str[16] = {0};
    const char *ptr = raw_request;
    const char *end = raw_request + raw_length;

    /* Extract method */
    const char *space = memchr(ptr, ' ', end - ptr);
    if (!space || (space - ptr) >= (int)sizeof(method_str)) return -1;
    memcpy(method_str, ptr, space - ptr);
    request->method = parse_method(method_str);

    /* Extract URI */
    ptr = space + 1;
    space = memchr(ptr, ' ', end - ptr);
    if (!space) return -1;
    size_t uri_len = space - ptr;
    if (uri_len >= MAX_URI_LENGTH) uri_len = MAX_URI_LENGTH - 1;
    memcpy(request->uri, ptr, uri_len);

    /* Extract HTTP version */
    ptr = space + 1;
    const char *newline = memchr(ptr, '\r', end - ptr);
    if (!newline) newline = memchr(ptr, '\n', end - ptr);
    if (!newline) return -1;
    size_t ver_len = newline - ptr;
    if (ver_len >= sizeof(request->version)) ver_len = sizeof(request->version) - 1;
    memcpy(request->version, ptr, ver_len);

    /* Move past the request line */
    ptr = newline;
    if (*ptr == '\r') ptr++;
    if (ptr < end && *ptr == '\n') ptr++;

    /* Parse headers */
    request->header_count = 0;
    while (ptr < end && request->header_count < MAX_HEADERS) {
        /* Check for end of headers */
        if (*ptr == '\r' || *ptr == '\n') {
            if (*ptr == '\r') ptr++;
            if (ptr < end && *ptr == '\n') ptr++;
            break;
        }

        const char *colon = memchr(ptr, ':', end - ptr);
        newline = memchr(ptr, '\r', end - ptr);
        if (!newline) newline = memchr(ptr, '\n', end - ptr);
        if (!colon || !newline) break;

        http_header_t *header = &request->headers[request->header_count];

        size_t name_len = colon - ptr;
        if (name_len >= sizeof(header->name)) name_len = sizeof(header->name) - 1;
        memcpy(header->name, ptr, name_len);

        /* Skip colon and whitespace */
        const char *val_start = colon + 1;
        while (val_start < newline && *val_start == ' ') val_start++;

        size_t val_len = newline - val_start;
        if (val_len >= sizeof(header->value)) val_len = sizeof(header->value) - 1;
        memcpy(header->value, val_start, val_len);

        request->header_count++;

        ptr = newline;
        if (*ptr == '\r') ptr++;
        if (ptr < end && *ptr == '\n') ptr++;
    }

    /* Remaining data is the body */
    if (ptr < end) {
        request->body = (char *)ptr;
        request->body_length = end - ptr;
    }

    return 0;
}

const char *get_header_value(const http_request_t *request, const char *name) {
    for (int i = 0; i < request->header_count; i++) {
        if (strcasecmp(request->headers[i].name, name) == 0) {
            return request->headers[i].value;
        }
    }
    return NULL;
}

