int format_response(const http_response_t *response, char *output_buffer, size_t buffer_size) {
    int written = snprintf(output_buffer, buffer_size,
        "HTTP/1.1 %d %s\r\n"
        "Content-Type: %s\r\n"
        "Content-Length: %zu\r\n"
        "Connection: keep-alive\r\n"
        "Server: EmbeddedHTTP/1.0\r\n"
        "\r\n",
        response->status_code,
        response->status_text,
        response->content_type,
        response->body_length);

    if (written < 0 || (size_t)written >= buffer_size) return -1;

    if (response->body && response->body_length > 0) {
        if ((size_t)written + response->body_length >= buffer_size) return -1;
        memcpy(output_buffer + written, response->body, response->body_length);
        written += (int)response->body_length;
        output_buffer[written] = '\0';
    }

    return written;
}

void free_response(http_response_t *response) {
    if (response && response->body) {
        free(response->body);
        response->body = NULL;
    }
}

/* Simulates receiving an HTTP request (for demonstration purposes) */
int simulate_receive_request(char *buffer, size_t buffer_size, int request_num) {
    const char *requests[] = {
        "GET / HTTP/1.1\r\n"
        "Host: localhost\r\n"
        "User-Agent: TestClient/1.0\r\n"
        "Accept: text/html\r\n"
        "\r\n",

        "GET /status HTTP/1.1\r\n"
        "Host: localhost\r\n"
        "User-Agent: TestClient/1.0\r\n"
        "Accept: application/json\r\n"
        "\r\n",

        "POST /api/data HTTP/1.1\r\n"
        "Host: localhost\r\n"
        "Content-Type: application/json\r\n"
        "Content-Length: 27\r\n"
        "\r\n"
        "{\"temperature\":25.3,\"id\":1}",

        "GET /api/data HTTP/1.1\r\n"
        "Host: localhost\r\n"
        "Accept: application/json\r\n"
        "\r\n",

        "GET /nonexistent HTTP/1.1\r\n"
        "Host: localhost\r\n"
        "\r\n",

        "DELETE /api/data HTTP/1.1\r\n"
        "Host: localhost\r\n"
        "\r\n",
    };

    int num_requests = sizeof(requests) / sizeof(requests[0]);
    int idx = request_num % num_requests;

    size_t len = strlen(requests[idx]);
    if (len >= buffer_size) return -1;

    memcpy(buffer, requests[idx], len);
    buffer[len] = '\0';
    return (int)len;
}

int main(void) {
    printf("=== Embedded HTTP Server Starting ===\n");
    printf("Initializing buffer pool...\n");

    buffer_pool_t *request_pool = buffer_pool_create(8, MAX_REQUEST_SIZE);
    buffer_pool_t *response_pool = buffer_pool_create(8, MAX_RESPONSE_SIZE);

    if (!request_pool || !response_pool) {
        fprintf(stderr, "Failed to initialize buffer pools\n");
        if (request_pool) buffer_pool_destroy(request_pool);
        if (response_pool) buffer_pool_destroy(response_pool);
        return 1;
    }

    printf("Buffer pools initialized. Starting request processing loop...\n\n");

    int max_iterations = 20; /* For demonstration; remove for actual embedded use */
    volatile bool server_running = true;
    int iteration = 0;

    while (server_running) {
        struct timespec start_time, end_time;
        clock_gettime(CLOCK_MONOTONIC, &start_time);

        /* Acquire buffers from pool */
        char *request_buffer = buffer_pool_acquire(request_pool);
        char *response_buffer = buffer_pool_acquire(response_pool);

        if (!request_buffer || !response_buffer) {
            fprintf(stderr, "[ERROR] Failed to acquire buffers\n");
            g_stats.errors++;
            if (request_buffer) buffer_pool_release(request_pool, request_buffer);
            if (response_buffer) buffer_pool_release(response_pool, response_buffer);
            continue;
        }

        /* Simulate receiving a request */
        int bytes_received = simulate_receive_request(request_buffer, MAX_REQUEST_SIZE, iteration);
        if (bytes_received <= 0) {
            fprintf(stderr, "[ERROR] Failed to receive request\n");
            g_stats.errors++;
            buffer_pool_release(request_pool, request_buffer);
            buffer_pool_release(response_pool, response_buffer);
            continue;
        }

        g_stats.bytes_received += bytes_received;

        /* Parse the HTTP request */
        http_request_t request;
        if (parse_request(request_buffer, bytes_received, &request) != 0) {
            fprintf(stderr, "[ERROR] Failed to parse request\n");
            g_stats.errors++;
            buffer_pool_release(request_pool, request_buffer);
            buffer_pool_release(response_pool, response_buffer);
            continue;
        }

        /* Process the request and generate a response */
        http_response_t response;
        if (process_request(&request, &response) != 0) {
            fprintf(stderr, "[ERROR] Failed to process request\n");
            g_stats.errors++;
            buffer_pool_release(request_pool, request_buffer);
            buffer_pool_release(response_pool, response_buffer);
            continue;
        }

        /* Format the response */
        int response_length = format_response(&response, response_buffer, MAX_RESPONSE_SIZE);
        if (response_length < 0) {
            fprintf(stderr, "[ERROR] Failed to format response\n");
            g_stats.errors++;
            free_response(&response);
            buffer_pool_release(request_pool, request_buffer);
            buffer_pool_release(response_pool, response_buffer);
            continue;
        }

        clock_gettime(CLOCK_MONOTONIC, &end_time);
        double elapsed_ms = (end_time.tv_sec - start_time.tv_sec) * 1000.0 +
                           (end_time.tv_nsec - start_time.tv_nsec) / 1000000.0;

        g_stats.requests_processed++;
        g_stats.bytes_sent += response_length;
        g_stats.total_processing_time_ms += elapsed_ms;

        /* Log the request/response */
        printf("[Request #%lu] %s %s -> %d %s (%.3f ms)\n",
            g_stats.requests_processed,
            method_to_string(request.method),
            request.uri,
            response.status_code,
            response.status_text,
            elapsed_ms);

        printf("  Headers: %d, Body: %zu bytes\n",
            request.header_count, request.body_length);
        printf("  Response: %d bytes\n", response_length);

        const char *host = get_header_value(&request, "Host");
        if (host) {
            printf("  Host: %s\n", host);
        }

        printf("  Response preview: %.100s...\n\n", response_buffer);

        /* Clean up */
        free_response(&response);
        buffer_pool_release(request_pool, request_buffer);
        buffer_pool_release(response_pool, response_buffer);

        iteration++;
        if (iteration >= max_iterations) {
            server_running = false;
        }
    }

    /* Print final statistics */
    printf("=== Server Statistics ===\n");
    printf("Requests processed: %lu\n", g_stats.requests_processed);
    printf("Bytes received:     %lu\n", g_stats.bytes_received);
    printf("Bytes sent:         %lu\n", g_stats.bytes_sent);
    printf("Errors:             %lu\n", g_stats.errors);
    printf("Avg processing time: %.3f ms\n",
        g_stats.requests_processed > 0 ?
            g_stats.total_processing_time_ms / g_stats.requests_processed : 0.0);
    printf("Total processing time: %.3f ms\n", g_stats.total_processing_time_ms);

    /* Cleanup */
    buffer_pool_destroy(request_pool);
    buffer_pool_destroy(response_pool);

    printf("\n=== Server Shutdown Complete ===\n");
    return 0;
}